var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"무리야, 이 기름 덩어리를 어떻게 다 치워?","JPN":"無理だよ。こんな油の量をどうやって回収すればいいの？","ENG":"This is impossible. How am I supposed to clean up all this oil?","TWN":"不行啦，怎麼可能有辦法把油漬全都清乾淨？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"나 혼자서는 오늘 하루 종일 해도 안 끝날 것 같은데…….","JPN":"私一人じゃ一日中掃除しても終わらない……","ENG":"I won't be able to finish it by today if I do this alone...","TWN":"我一個人清一整天也清不完吧……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"미안해. 결국 사진은 못 찾았어.","JPN":"ごめんね、写真部のみんな。\\n結局写真は見つけることが出来なかった。","ENG":"Sorry. I couldn't find your photos.","TWN":"對不起，結果還是沒找到照片。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"응? 어떻게든 전시회를 열 수 있는 방법?","JPN":"えっ？　なんとか展示会を実施できる方法？","ENG":"Hmm? A way to still hold the exhibition?","TWN":"嗯？還有什麼方法可以舉行攝影展嗎？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"미안…… 나는 어떻게 해야 할지 잘 모르겠어…….","JPN":"ごめんなさい……私にはいい方法が思いつかなくて……","ENG":"Sorry... But I'm not sure what to do...","TWN":"抱歉……我想不到方法……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무리 합을 맞추고 진행한다고 해도 검을 다루는 일은 매우 위험하죠.","JPN":"事前に打ち合わせをするとしても、剣を扱うのはとても危険なことです。","ENG":"Even if everything is choreographed, handling a real sword on stage is dangerous.","TWN":"不過就算我願意配合你們，但畢竟刀劍無眼，還是有危險性的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유감스럽지만, 저와 동등한 실력자가 없다면 이 제안은 받아들일 수 없군요.","JPN":"申し上げにくいですが、\\n私と同等の実力者がいないのなら、この提案を引き受けることはできません。","ENG":"I'm sorry, but I cannot accept this part unless the other actor is as skilled with swords as I am.","TWN":"很抱歉，若是沒有與我實力相當的對手，請恕我無法答應。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"어이, 들었어? 학원제에 불참하게 된 동아리가 늘고 있대. 학생회에 도움을 요청했는데도 해결이 안 됐다나 봐.","JPN":"おい、聞いたか？　いくつかの部の出し物が中止になったらしい。\\n生徒会にトラブルの報告をしていたにも関わらずだってさ。","ENG":"Hey, did you hear? More and more clubs are withdrawing from the festival. Something about not getting their problems solved even though they asked the Student Council for help.","TWN":"喂喂，你們有聽說嗎？聽說越來越多社團不參加學園祭欸。看來就算求助於學生會也沒用。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"학생회 녀석들은 뭘 하고 있는 거야? 학원제 관리가 전혀 되고 있지 않잖아.","JPN":"生徒会はちゃんと仕事してるの？\\n学園祭の管理が全然できてないじゃない。","ENG":"What is the Student Council even doing? It's like they're not even trying to supervise the festival.","TWN":"學生會的人是在做什麼？連個學園祭都搞不定！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"역대 최악의 학생회와 역대 최악의 학원제야. 진짜.","JPN":"歴代最悪の生徒会に歴代最悪の学園祭だよ、まったく。","ENG":"This year has the worst Student Council and the worst festival ever, really.","TWN":"這根本是歷年來最糟最慘的學園祭，真是的！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그러니까…….","JPN":"つまり……","ENG":"So...","TWN":"現在……"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"수영장에 떠다니는 기름의 악취가 퍼져서, 부스를 닫아야 하는 동아리가 계속 나오고 있고.","JPN":"プールに浮いていた油の悪臭が広がり、\\n中止を余儀なくされた他の部の屋台が続出していて……","ENG":"Due to the foul stench emanating from the blobs of oil in the pool, an increasing number of clubs have closed their booths.","TWN":"因為泳池的油漬惡臭飄出來，導致有越來越多的社團的攤位必須關閉。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사진을 잃어버린 사진부는 전시관에서 미술품을 훼손하다가 싸움이 일어났으며…….","JPN":"展示写真をなくした写真部は、会場で美術部の展示品を壊して大喧嘩になり……","ENG":"After having their photos stolen, the photography club attempted to sabotage the art club's works and got into a fight...","TWN":"而照片不見的攝影部，則是因為破壞展覽館裡的美術品，導致雙方發生衝突……"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"연극부에서는 동아리 내부 균열로 폐부 위기……라는 말인가요?","JPN":"演劇部では部内の対立によって廃部の危機に……ということですか？","ENG":"And the theater club is on the brink of disbanding due to internal conflict... Correct?","TWN":"戲劇部因為內鬨，吵到快要……廢社？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생들의 안전을 생각한 일이었는데…… 일이 이렇게 될 줄은 몰랐군요.","JPN":"生徒たちの安全のために務めてきたつもりでしたが……\\nこんなことになるとは。","ENG":"I was prioritizing everyone's safety... but I never imagined things would end up like this.","TWN":"原本只是顧慮到學生的安全……沒想到事情會變成這樣。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"미안, 최선을 다했는데…….","JPN":"ごめん。ベストは尽くしたんだけど……","ENG":"Sorry, I tried my best, but...","TWN":"對不起，我已經盡力了……"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"나 혼자서는 문제를 제대로 해결하지 못했어……. 미안해 루루.","JPN":"上手くトラブルを解決できなかった……ごめんね、ルル。","ENG":"I couldn't resolve the issue on my own... I'm sorry, Lulu.","TWN":"光靠我自己一個人沒辦法解決問題……對不起，魯魯。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아니. 학원제가 이렇게 된 건 학생회인 너희들 때문이 아니야.","JPN":"いや、学園祭がこうなってしまったのは生徒会のみんなのせいではない。","ENG":"No. It is not your fault the festival ended up like this.","TWN":"不，學園祭會變成這樣，不是你們的問題。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"진짜 원인은 실행위원장인 내 역량부족이겠지. 미안하다.","JPN":"一番の原因は、学園祭実行委員長である俺の力不足だ。すまない。","ENG":"It's my incompetence as the head of the executive committee. My apologies.","TWN":"而是身為執行委員長的我辦事不力，我很抱歉。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 사과한다고 뭐가 달라져?","JPN":"ふん！　謝っても意味がないわ！","ENG":"Hmph! Like your apology is gonna change anything!","TWN":"哼！道歉有用嗎？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"학생회 전체 평판이 바닥으로 떨어졌는데 이제와서 어떻게 책임질 건데?","JPN":"生徒会全体の評判が地に落ちたのに、今さらどうやって責任を負うつもり？","ENG":"The Student Council's reputation is in the gutter. How are you going to make up for that?","TWN":"現在學生們對於學生會的評價已經跌落谷底，你要怎麼負責？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양, 그만해요. 누군가를 추궁해서 해결될 문제가 아니잖아요.","JPN":"ナイエルさん、やめましょう。誰かを責めても解決にはなりませんよ。","ENG":"Naielle, enough is enough. Interrogating others won't solve the issue.","TWN":"奈爾，別這樣，現在就算找個人來背黑鍋問題也不會解決。"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니, 그만 하긴 뭘 그만해?","JPN":"いいえ、何をやめるっていうのよ？","ENG":"What do you mean, enough is enough?","TWN":"什麼別這樣？"},"stage":{"bg":"GEASS_ROOM","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};